// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import {ECDSA} from "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";

/**
 * @title WeRgame
 * @dev Comprehensive smart contract for prediction market platform
 * Handles market creation, trading, boost predictions, and jackpot management
 */
contract WeRgame is ReentrancyGuard {
    using SafeERC20 for IERC20;

    address public deployer;
    address public superAdmin;
    mapping(address => bool) public admins;

    /// @notice Platform currency token (Base USDC). All pools and payouts are denominated in this token.
    IERC20 public immutable usdc;
    
    // Fee structure (in basis points, 10000 = 100%)
    uint256 public platformFee; // For boost predictions
    uint256 public boostJackpotFee;
    uint256 public marketPlatformFee;
    uint256 public freeJackpotFee;
    
    // Market status enum
    enum MarketStatus {
        Upcoming,
        Active,
        Locked,
        Resolved
    }
    
    // Market structure
    struct Market {
        uint256 marketId;
        bool isPoll; // true for poll, false for match
        MarketStatus status;
        string[] options; // Options/outcomes for this market
        mapping(string => uint256) liquidity; // Liquidity per option
        mapping(string => uint256) shares; // Total shares per option
        uint256 totalLiquidity;
        bool resolved;
        string winningOption; // Set when resolved
        uint256 createdAt;
        uint256 resolvedAt;
    }
    
    // Boost prediction structure
    struct BoostPrediction {
        address user;
        uint256 marketId;
        string outcome;
        uint256 stakeAmount;
        uint256 totalStake;
        bool claimed;
    }
    
    // Market trading position
    struct MarketPosition {
        address user;
        string outcome;
        uint256 shares;
        uint256 totalInvested;
    }
    
    // Mappings
    mapping(uint256 => Market) public markets;
    mapping(uint256 => mapping(address => mapping(string => BoostPrediction))) public boostPredictions; // marketId => user => outcome => prediction
    mapping(uint256 => mapping(address => mapping(string => MarketPosition))) public marketPositions; // marketId => user => outcome => position
    mapping(uint256 => mapping(address => uint256)) public claimableBalances; // marketId => user => claimable amount (legacy/total)
    mapping(uint256 => mapping(address => uint256)) public claimableBoost;    // marketId => user => boost claimable
    mapping(uint256 => mapping(address => uint256)) public claimableMarket;  // marketId => user => market claimable
    mapping(address => uint256) public jackpotBalances; // user => jackpot balance
    
    uint256 public nextMarketId;
    uint256 public jackpotPool;
    /// @dev Pool for paying Boost and Market prediction wins; funded by deployer and by boost stakes
    uint256 public claimPredictionWinsPool;

    /// @notice Backend / ops wallet that signs authorized claims (set by deployer)
    address public claimAuthSigner;
    /// @notice Replay protection for signature-based prediction claims
    mapping(bytes32 => bool) public usedAuthPredictionClaims;
    /// @notice Replay protection for signature-based jackpot withdrawals
    mapping(bytes32 => bool) public usedJackpotWithdrawNonces;
    /// @notice USDC credited to users for orderbook trading (deposit / settlement)
    mapping(address => uint256) public tradingVaultBalances;
    /// @notice Sum of all tradingVaultBalances — used to prevent superAdmin draining user vault collateral
    uint256 public totalTradingVaultLiabilities;
    mapping(bytes32 => bool) public usedTradingVaultWithdrawNonces;
    /// @notice Replay for orderbook position claims (separate from boost/market auth key space)
    mapping(bytes32 => bool) public usedOrderbookClaimKeys;
    /// @notice On-chain reference liquidity for YES/NO books per outcome option (USDC units)
    mapping(uint256 => mapping(string => uint256)) public orderbookLiquidityYes;
    mapping(uint256 => mapping(string => uint256)) public orderbookLiquidityNo;
    mapping(uint256 => mapping(string => uint256)) public orderbookSharesYes;
    mapping(uint256 => mapping(string => uint256)) public orderbookSharesNo;
    
    // Events
    event MarketCreated(uint256 indexed marketId, bool isPoll, string[] options);
    event MarketStatusUpdated(uint256 indexed marketId, MarketStatus status);
    event MarketResolved(uint256 indexed marketId, string winningOption);
    event LiquidityAdded(uint256 indexed marketId, string option, uint256 amount);
    event FeesUpdated(uint256 platformFee, uint256 boostJackpotFee, uint256 marketPlatformFee, uint256 freeJackpotFee);
    event BoostStaked(uint256 indexed marketId, address indexed user, string outcome, uint256 amount);
    event BoostStakeAdded(uint256 indexed marketId, address indexed user, uint256 amount);
    event BoostStakeWithdrawn(uint256 indexed marketId, address indexed user, uint256 amount);
    event BoostClaimed(uint256 indexed marketId, address indexed user, uint256 amount);
    event MarketBought(uint256 indexed marketId, address indexed user, string outcome, uint256 ethAmount, uint256 shares);
    event MarketSold(uint256 indexed marketId, address indexed user, string outcome, uint256 shares, uint256 ethAmount);
    event MarketClaimed(uint256 indexed marketId, address indexed user, string outcome, uint256 amount);
    event JackpotFunded(uint256 amount);
    event JackpotWithdrawn(address indexed user, uint256 amount);
    event JackpotPoolWithdrawn(address indexed to, uint256 amount);
    event FundsTransferred(address indexed to, uint256 amount);
    event ClaimPredictionWinsPoolFunded(uint256 amount);
    event ClaimPredictionWinsPoolWithdrawn(address indexed to, uint256 amount);
    event PredictionWinsClaimed(uint256 indexed marketId, address indexed user, uint256 amount);
    event TradingVaultDeposited(address indexed user, uint256 amount);
    event TradingVaultWithdrawn(address indexed user, uint256 amount);
    event OrderbookLiquidityBatchAdded(uint256 indexed marketId, uint256 totalAmount);
    event OrderbookSettlementsApplied(
        uint256 indexed marketId,
        uint256 legs,
        uint256 feeToClaimPool,
        uint256 feeToJackpotPool
    );
    event OrderbookPositionClaimed(uint256 indexed marketId, address indexed user, string positionKey, uint256 amount);
    event ContractMigratedForUpgrade(address indexed to, uint256 amount);
    
    modifier onlyDeployer() {
        require(msg.sender == deployer, "Only deployer");
        _;
    }
    
    modifier onlySuperAdmin() {
        require(msg.sender == superAdmin || msg.sender == deployer, "Only superAdmin");
        _;
    }

    modifier onlyAdmin() {
        require(msg.sender == deployer || admins[msg.sender], "Only admin");
        _;
    }
    
    modifier validMarket(uint256 marketId) {
        require(markets[marketId].marketId != 0, "Market does not exist");
        _;
    }

    function _marketHasOption(uint256 marketId, string memory option) internal view returns (bool) {
        Market storage market = markets[marketId];
        for (uint256 i = 0; i < market.options.length; i++) {
            if (keccak256(bytes(market.options[i])) == keccak256(bytes(option))) {
                return true;
            }
        }
        return false;
    }

    function _applyVaultDelta(address user, int256 delta) internal {
        if (delta > 0) {
            tradingVaultBalances[user] += uint256(delta);
            totalTradingVaultLiabilities += uint256(delta);
        } else if (delta < 0) {
            uint256 dec = uint256(-delta);
            require(tradingVaultBalances[user] >= dec, "Insufficient vault");
            tradingVaultBalances[user] -= dec;
            require(totalTradingVaultLiabilities >= dec, "Vault liability underflow");
            totalTradingVaultLiabilities -= dec;
        }
    }

    function _applyShareDelta(uint256 marketId, address user, string memory positionKey, int256 sharesDelta, int256 investedDelta) internal {
        MarketPosition storage position = marketPositions[marketId][user][positionKey];
        if (position.user == address(0)) {
            position.user = user;
            position.outcome = positionKey;
        }
        if (sharesDelta > 0) {
            position.shares += uint256(sharesDelta);
        } else if (sharesDelta < 0) {
            uint256 dec = uint256(-sharesDelta);
            require(position.shares >= dec, "Insufficient shares");
            position.shares -= dec;
        }
        if (investedDelta > 0) {
            position.totalInvested += uint256(investedDelta);
        } else if (investedDelta < 0) {
            uint256 dec2 = uint256(-investedDelta);
            require(position.totalInvested >= dec2, "Invested underflow");
            position.totalInvested -= dec2;
        }
    }
    
    /// @dev EIP-191 personal_sign over keccak256(abi.encodePacked(...fields...))
    function _recoverAuthSigner(bytes32 messageHash, bytes calldata signature) internal pure returns (address) {
        bytes32 ethSigned = keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", messageHash));
        return ECDSA.recover(ethSigned, signature);
    }
    
    constructor(address usdcToken) {
        require(usdcToken != address(0), "Invalid USDC token");
        deployer = msg.sender;
        superAdmin = msg.sender;
        admins[msg.sender] = true;
        usdc = IERC20(usdcToken);
        
        // Default fees (in basis points: 1000 = 10%, 500 = 5%)
        platformFee = 1000; // 10%
        boostJackpotFee = 500; // 5%
        marketPlatformFee = 500; // 5%
        freeJackpotFee = 500; // 5%
        
        nextMarketId = 1;
        // Default to deployer; change with setClaimAuthSigner if backend uses a dedicated ops key.
        claimAuthSigner = msg.sender;
    }
    
    /**
     * @dev Create a new market (match or poll)
     * @param isPoll true if poll, false if match
     * @param options array of outcome options
     */
    function createMarket(bool isPoll, string[] memory options) external onlyAdmin returns (uint256) {
        require(options.length >= 2, "Must have at least 2 options");
        
        uint256 marketId = nextMarketId++;
        Market storage market = markets[marketId];
        market.marketId = marketId;
        market.isPoll = isPoll;
        market.status = MarketStatus.Upcoming;
        market.createdAt = block.timestamp;
        
        // Initialize options
        for (uint256 i = 0; i < options.length; i++) {
            market.options.push(options[i]);
            market.liquidity[options[i]] = 0;
            market.shares[options[i]] = 0;
        }
        
        emit MarketCreated(marketId, isPoll, options);
        return marketId;
    }
    
    /**
     * @dev Update market status
     */
    function updateMarketStatus(uint256 marketId, MarketStatus status) external onlyAdmin validMarket(marketId) {
        markets[marketId].status = status;
        emit MarketStatusUpdated(marketId, status);
    }
    
    /**
     * @dev Add initial liquidity to a market option
     */
    function addLiquidity(uint256 marketId, string memory option, uint256 amount) external onlyAdmin validMarket(marketId) {
        require(amount > 0, "Amount must be greater than 0");
        
        Market storage market = markets[marketId];
        require(market.status == MarketStatus.Upcoming || market.status == MarketStatus.Active, "Market not active");
        
        // Verify option exists
        bool optionExists = false;
        for (uint256 i = 0; i < market.options.length; i++) {
            if (keccak256(bytes(market.options[i])) == keccak256(bytes(option))) {
                optionExists = true;
                break;
            }
        }
        require(optionExists, "Invalid option");
        
        usdc.safeTransferFrom(msg.sender, address(this), amount);

        market.liquidity[option] += amount;
        market.totalLiquidity += amount;
        
        emit LiquidityAdded(marketId, option, amount);
    }
    
    /**
     * @dev Resolve a market
     */
    function resolveMarket(uint256 marketId, string memory winningOption) external onlyAdmin validMarket(marketId) {
        Market storage market = markets[marketId];
        require(market.status != MarketStatus.Resolved, "Already resolved");
        
        // Verify option exists
        bool optionExists = false;
        for (uint256 i = 0; i < market.options.length; i++) {
            if (keccak256(bytes(market.options[i])) == keccak256(bytes(winningOption))) {
                optionExists = true;
                break;
            }
        }
        require(optionExists, "Invalid winning option");
        
        market.status = MarketStatus.Resolved;
        market.resolved = true;
        market.winningOption = winningOption;
        market.resolvedAt = block.timestamp;
        
        emit MarketResolved(marketId, winningOption);
    }
    
    /**
     * @dev Set fees (in basis points)
     */
    /**
     * @dev Set wallet whose signatures authorize user claims (off-chain payout amount). Use the same key as CLAIM_AUTH_PRIVATE_KEY on the API.
     */
    function setClaimAuthSigner(address signer) external onlyDeployer {
        require(signer != address(0), "Invalid signer");
        claimAuthSigner = signer;
    }
    
    function setFees(
        uint256 _platformFee,
        uint256 _boostJackpotFee,
        uint256 _marketPlatformFee,
        uint256 _freeJackpotFee
    ) external onlyDeployer {
        require(_platformFee <= 10000 && _boostJackpotFee <= 10000 && 
                _marketPlatformFee <= 10000 && _freeJackpotFee <= 10000, "Fees cannot exceed 100%");
        
        platformFee = _platformFee;
        boostJackpotFee = _boostJackpotFee;
        marketPlatformFee = _marketPlatformFee;
        freeJackpotFee = _freeJackpotFee;
        
        emit FeesUpdated(_platformFee, _boostJackpotFee, _marketPlatformFee, _freeJackpotFee);
    }
    
    /**
     * @dev Get current fees
     */
    function getFees() external view returns (
        uint256 _platformFee,
        uint256 _boostJackpotFee,
        uint256 _marketPlatformFee,
        uint256 _freeJackpotFee
    ) {
        return (platformFee, boostJackpotFee, marketPlatformFee, freeJackpotFee);
    }
    
    /**
     * @dev Get options for a market (so frontend can validate outcome before staking)
     */
    function getMarketOptions(uint256 marketId) external view validMarket(marketId) returns (string[] memory) {
        return markets[marketId].options;
    }
    
    /**
     * @dev Stake USDC for boost prediction. Net stake + platform fee fund `claimPredictionWinsPool`
     *      (same pool `claimPredictionWinsWithAuth` pays from); jackpot fee funds `jackpotPool`.
     */
    function stakeBoost(uint256 marketId, string memory outcome, uint256 amount) external validMarket(marketId) nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        Market storage market = markets[marketId];
        require(market.status == MarketStatus.Upcoming || market.status == MarketStatus.Active, "Market not active");
        
        // Verify option exists
        bool optionExists = false;
        for (uint256 i = 0; i < market.options.length; i++) {
            if (keccak256(bytes(market.options[i])) == keccak256(bytes(outcome))) {
                optionExists = true;
                break;
            }
        }
        require(optionExists, "Invalid outcome");
        
        usdc.safeTransferFrom(msg.sender, address(this), amount);

        uint256 platformFeeAmount = (amount * platformFee) / 10000;
        uint256 jackpotFeeAmount = (amount * freeJackpotFee) / 10000;
        uint256 netStake = amount - platformFeeAmount - jackpotFeeAmount;
        require(netStake > 0, "Stake too small after fees");
        
        // Update or create boost prediction
        BoostPrediction storage prediction = boostPredictions[marketId][msg.sender][outcome];
        if (prediction.user == address(0)) {
            // New prediction
            prediction.user = msg.sender;
            prediction.marketId = marketId;
            prediction.outcome = outcome;
            prediction.stakeAmount = netStake;
            prediction.totalStake = netStake;
        } else {
            // Update existing prediction
            prediction.totalStake += netStake;
        }
        
        claimPredictionWinsPool += netStake + platformFeeAmount;
        jackpotPool += jackpotFeeAmount;
        
        emit BoostStaked(marketId, msg.sender, outcome, netStake);
    }
    
    /**
     * @dev Add more stake to existing boost prediction
     */
    function addBoostStake(uint256 marketId, string memory outcome, uint256 amount) external validMarket(marketId) nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        Market storage market = markets[marketId];
        require(market.status == MarketStatus.Upcoming || market.status == MarketStatus.Active, "Market not active");
        
        BoostPrediction storage prediction = boostPredictions[marketId][msg.sender][outcome];
        require(prediction.user == msg.sender, "No existing prediction");
        
        usdc.safeTransferFrom(msg.sender, address(this), amount);

        uint256 platformFeeAmount = (amount * platformFee) / 10000;
        uint256 jackpotFeeAmount = (amount * freeJackpotFee) / 10000;
        uint256 netStake = amount - platformFeeAmount - jackpotFeeAmount;
        require(netStake > 0, "Stake too small after fees");
        
        prediction.totalStake += netStake;
        
        claimPredictionWinsPool += netStake + platformFeeAmount;
        jackpotPool += jackpotFeeAmount;
        
        emit BoostStakeAdded(marketId, msg.sender, netStake);
    }
    
    /**
     * @dev Withdraw stake from boost prediction (only before resolution)
     */
    function withdrawBoostStake(uint256 marketId, string memory outcome, uint256 amount) external validMarket(marketId) nonReentrant {
        Market storage market = markets[marketId];
        require(market.status == MarketStatus.Upcoming || market.status == MarketStatus.Active, "Market not active");
        
        BoostPrediction storage prediction = boostPredictions[marketId][msg.sender][outcome];
        require(prediction.user == msg.sender, "No prediction found");
        require(prediction.totalStake >= amount, "Insufficient stake");
        
        prediction.totalStake -= amount;
        require(claimPredictionWinsPool >= amount, "Insufficient claim pool");
        claimPredictionWinsPool -= amount;
        
        usdc.safeTransfer(msg.sender, amount);
        
        emit BoostStakeWithdrawn(marketId, msg.sender, amount);
    }
    
    /**
     * @dev Claim boost prediction winnings — REMOVED: use claimPredictionWinsWithAuth only.
     * Legacy claimBoost() allowed unsigned claims when admin set claimableBalances.
     */

    /**
     * @dev Set claimable balance for a user (legacy admin bookkeeping; not used for user claims).
     */
    function setClaimableBalance(uint256 marketId, address user, uint256 amount) external onlyAdmin {
        claimableBalances[marketId][user] = amount;
    }
    
    /**
     * @dev Set claimable boost amount for a user (called after resolution).
     */
    function setClaimableBoost(uint256 marketId, address user, uint256 amount) external onlyAdmin {
        claimableBoost[marketId][user] = amount;
    }
    
    /**
     * @dev Set claimable market amount for a user (admin bookkeeping after resolve; claims use WithAuth).
     */
    function setClaimableMarket(uint256 marketId, address user, uint256 amount) external onlyAdmin {
        claimableMarket[marketId][user] = amount;
    }

    /**
     * @dev Claim boost or market winnings using a signature from `claimAuthSigner`.
     * Unsigned claimPredictionWins() removed — all user payouts require backend authorization.
     */
    function claimPredictionWinsWithAuth(
        uint256 marketId,
        bool isBoost,
        uint256 amount,
        bytes32 predictionId,
        uint256 deadline,
        bytes calldata signature
    ) external validMarket(marketId) nonReentrant {
        require(claimAuthSigner != address(0), "Claim signer not set");
        require(block.timestamp <= deadline, "Expired");
        require(amount > 0, "Zero amount");

        bytes32 authKey = keccak256(abi.encodePacked(msg.sender, predictionId));
        require(!usedAuthPredictionClaims[authKey], "Already claimed");

        bytes32 messageHash = keccak256(
            abi.encodePacked(
                msg.sender,
                marketId,
                isBoost,
                amount,
                predictionId,
                deadline,
                block.chainid,
                address(this)
            )
        );
        address recovered = _recoverAuthSigner(messageHash, signature);
        require(recovered != address(0) && recovered == claimAuthSigner, "Invalid signature");

        Market storage market = markets[marketId];
        require(market.resolved, "Market not resolved");
        string memory winningOption = market.winningOption;

        if (isBoost) {
            BoostPrediction storage boostPred = boostPredictions[marketId][msg.sender][winningOption];
            require(boostPred.user == msg.sender && boostPred.totalStake > 0 && !boostPred.claimed, "Not a boost participant");
            boostPred.claimed = true;
        } else {
            MarketPosition storage pos = marketPositions[marketId][msg.sender][winningOption];
            require(pos.user == msg.sender && pos.shares > 0, "Not a market participant");
            pos.shares = 0;
            pos.totalInvested = 0;
        }

        require(claimPredictionWinsPool >= amount, "Insufficient claim pool");
        usedAuthPredictionClaims[authKey] = true;
        claimPredictionWinsPool -= amount;
        usdc.safeTransfer(msg.sender, amount);
        emit PredictionWinsClaimed(marketId, msg.sender, amount);
    }
    
    /**
     * @dev Withdraw from jackpot pool using a signature from `claimAuthSigner`.
     * Enforces per-user on-chain `jackpotBalances` (synced from admin/backend on resolve).
     */
    function withdrawJackpotWithAuth(
        uint256 amount,
        bytes32 nonce,
        uint256 deadline,
        bytes calldata signature
    ) external nonReentrant {
        require(claimAuthSigner != address(0), "Claim signer not set");
        require(block.timestamp <= deadline, "Expired");
        require(amount > 0, "Zero amount");
        require(!usedJackpotWithdrawNonces[nonce], "Nonce used");

        bytes32 messageHash = keccak256(
            abi.encodePacked(msg.sender, amount, nonce, deadline, block.chainid, address(this))
        );
        address recovered = _recoverAuthSigner(messageHash, signature);
        require(recovered != address(0) && recovered == claimAuthSigner, "Invalid signature");

        require(jackpotBalances[msg.sender] >= amount, "Insufficient balance");
        require(jackpotPool >= amount, "Insufficient jackpot pool");
        usedJackpotWithdrawNonces[nonce] = true;
        jackpotBalances[msg.sender] -= amount;
        jackpotPool -= amount;

        usdc.safeTransfer(msg.sender, amount);
        emit JackpotWithdrawn(msg.sender, amount);
    }

    /**
     * @dev Fund the claim prediction wins pool (super admin or deployer).
     */
    function fundClaimPredictionWinsPool(uint256 amount) external onlySuperAdmin {
        require(amount > 0, "Amount must be greater than 0");
        usdc.safeTransferFrom(msg.sender, address(this), amount);
        claimPredictionWinsPool += amount;
        emit ClaimPredictionWinsPoolFunded(amount);
    }
    
    /**
     * @dev Withdraw from claim prediction wins pool (deployer only).
     */
    function withdrawFromClaimPredictionWinsPool(address payable to, uint256 amount) external onlySuperAdmin nonReentrant {
        require(to != address(0), "Invalid recipient");
        require(to != address(this), "Cannot send to contract");
        require(amount > 0, "Amount must be greater than 0");
        require(claimPredictionWinsPool >= amount, "Insufficient pool balance");
        claimPredictionWinsPool -= amount;
        usdc.safeTransfer(to, amount);
        emit ClaimPredictionWinsPoolWithdrawn(to, amount);
    }
    
    /**
     * @dev Buy shares in market (fixed-sum AMM)
     */
    function buyMarketShares(uint256 marketId, string memory outcome, uint256 amount) external validMarket(marketId) nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        Market storage market = markets[marketId];
        require(market.status == MarketStatus.Upcoming || market.status == MarketStatus.Active, "Market not active");
        
        // Verify option exists
        bool optionExists = false;
        for (uint256 i = 0; i < market.options.length; i++) {
            if (keccak256(bytes(market.options[i])) == keccak256(bytes(outcome))) {
                optionExists = true;
                break;
            }
        }
        require(optionExists, "Invalid outcome");
        
        // Calculate fees
        usdc.safeTransferFrom(msg.sender, address(this), amount);

        uint256 platformFeeAmount = (amount * marketPlatformFee) / 10000;
        uint256 freeJackpotFeeAmount = (amount * freeJackpotFee) / 10000;
        uint256 netAmount = amount - platformFeeAmount - freeJackpotFeeAmount;
        require(netAmount > 0, "Amount too small after fees");
        
        // Calculate current price (liquidity / total liquidity)
        uint256 currentPrice = market.totalLiquidity > 0 
            ? (market.liquidity[outcome] * 10000) / market.totalLiquidity 
            : (10000 / market.options.length); // Equal distribution if no liquidity
        
        // Calculate shares received
        uint256 shares = (netAmount * 10000) / currentPrice;
        
        // Update liquidity (fixed-sum AMM: buying increases selected option's liquidity)
        market.liquidity[outcome] += netAmount;
        market.totalLiquidity += netAmount;
        market.shares[outcome] += shares;
        
        // Update user position
        MarketPosition storage position = marketPositions[marketId][msg.sender][outcome];
        if (position.user == address(0)) {
            position.user = msg.sender;
            position.outcome = outcome;
        }
        position.shares += shares;
        position.totalInvested += netAmount;
        
        // Market buys fund the claim prediction wins pool; jackpot fee share goes to jackpotPool
        claimPredictionWinsPool += netAmount + platformFeeAmount;
        if (freeJackpotFeeAmount > 0) {
            jackpotPool += freeJackpotFeeAmount;
        }
        
        emit MarketBought(marketId, msg.sender, outcome, netAmount, shares);
    }
    
    /**
     * @dev Sell shares in market
     */
    function sellMarketShares(uint256 marketId, string memory outcome, uint256 shares) external validMarket(marketId) nonReentrant {
        Market storage market = markets[marketId];
        require(market.status == MarketStatus.Upcoming || market.status == MarketStatus.Active, "Market not active");
        
        MarketPosition storage position = marketPositions[marketId][msg.sender][outcome];
        require(position.user == msg.sender, "No position found");
        require(position.shares >= shares, "Insufficient shares");
        
        // Calculate current price
        uint256 currentPrice = market.totalLiquidity > 0 
            ? (market.liquidity[outcome] * 10000) / market.totalLiquidity 
            : (10000 / market.options.length);
        
        // Calculate payout
        uint256 payout = (shares * currentPrice) / 10000;
        require(market.liquidity[outcome] >= payout, "Insufficient market liquidity");
        require(market.shares[outcome] >= shares, "Insufficient market shares");
        
        // Update liquidity (selling decreases selected option's liquidity)
        market.liquidity[outcome] -= payout;
        market.totalLiquidity -= payout;
        market.shares[outcome] -= shares;
        
        // Update user position
        position.shares -= shares;
        position.totalInvested -= (payout * position.totalInvested) / (position.shares + shares);
        
        // Deduct from claim prediction wins pool when user sells (pool was credited on buy)
        require(claimPredictionWinsPool >= payout, "Insufficient claim pool");
        claimPredictionWinsPool -= payout;
        
        usdc.safeTransfer(msg.sender, payout);
        
        emit MarketSold(marketId, msg.sender, outcome, shares, payout);
    }
    
    /**
     * @dev Claim market winnings after resolution
     */
    function claimMarket(uint256 marketId, string memory outcome) external validMarket(marketId) nonReentrant {
        Market storage market = markets[marketId];
        require(market.resolved, "Market not resolved");
        require(keccak256(bytes(market.winningOption)) == keccak256(bytes(outcome)), "Not winning outcome");
        
        MarketPosition storage position = marketPositions[marketId][msg.sender][outcome];
        require(position.user == msg.sender, "No position found");
        require(position.shares > 0, "No shares to claim");
        
        // Calculate claimable amount (backend will set this)
        uint256 claimable = claimableBalances[marketId][msg.sender];
        require(claimable > 0, "No claimable balance");
        require(claimPredictionWinsPool >= claimable, "Insufficient claim pool");
        
        claimableBalances[marketId][msg.sender] = 0;
        claimPredictionWinsPool -= claimable;
        
        usdc.safeTransfer(msg.sender, claimable);
        
        emit MarketClaimed(marketId, msg.sender, outcome, claimable);
    }
    
    /**
     * @dev Get current price for an option (in basis points)
     */
    function getPrice(uint256 marketId, string memory outcome) external view validMarket(marketId) returns (uint256) {
        Market storage market = markets[marketId];
        if (market.totalLiquidity == 0) {
            return (10000 / market.options.length);
        }
        return (market.liquidity[outcome] * 10000) / market.totalLiquidity;
    }
    
    /**
     * @dev Get user's market position
     */
    function getUserPosition(uint256 marketId, address user, string memory outcome) external view validMarket(marketId) returns (uint256 shares, uint256 totalInvested) {
        MarketPosition storage position = marketPositions[marketId][user][outcome];
        return (position.shares, position.totalInvested);
    }
    
    /**
     * @dev Get user's boost prediction
     */
    function getBoostPrediction(uint256 marketId, address user, string memory outcome) external view validMarket(marketId) returns (
        address _user,
        uint256 _totalStake,
        bool _claimed
    ) {
        BoostPrediction storage prediction = boostPredictions[marketId][user][outcome];
        return (prediction.user, prediction.totalStake, prediction.claimed);
    }
    
    /**
     * @dev Fund jackpot pool (deployer only). Transfers USDC into contract jackpotPool.
     */
    function fundJackpotPool(uint256 amount) external onlyDeployer {
        require(amount > 0, "Amount must be greater than 0");
        usdc.safeTransferFrom(msg.sender, address(this), amount);
        jackpotPool += amount;
        emit JackpotFunded(amount);
    }

    /**
     * @dev User jackpot payout — signature required (withdrawJackpot without auth removed).
     */
    function setJackpotBalance(address user, uint256 amount) external onlyAdmin {
        jackpotBalances[user] = amount;
    }

    /**
     * @dev Batch-set on-chain jackpot balances after resolve (gas-efficient sync with off-chain ledger).
     */
    function batchSetJackpotBalances(address[] calldata users, uint256[] calldata amounts) external onlyAdmin {
        require(users.length == amounts.length, "Length mismatch");
        for (uint256 i = 0; i < users.length; i++) {
            jackpotBalances[users[i]] = amounts[i];
        }
    }
    
    /**
     * @dev Withdraw from jackpot pool (deployer only)
     */
    function withdrawFromJackpotPool(address payable to, uint256 amount) external onlyDeployer nonReentrant {
        require(to != address(0), "Invalid recipient");
        require(to != address(this), "Cannot send to contract");
        require(amount > 0, "Amount must be greater than 0");
        require(jackpotPool >= amount, "Insufficient pool balance");
        jackpotPool -= amount;
        usdc.safeTransfer(to, amount);

        emit JackpotPoolWithdrawn(to, amount);
    }
    
    /**
     * @dev Get contract balance
     */
    function getContractBalance() external view returns (uint256) {
        return usdc.balanceOf(address(this));
    }
    
    /**
     * @dev Transfer surplus USDC (above claim pool + jackpot + user vault liabilities).
     *      Callable by deployer or superAdmin. For full contract drain before upgrade, use
     *      `migrateAllFundsForUpgrade`.
     */
    function transferFunds(address payable to, uint256 amount) external onlySuperAdmin nonReentrant {
        require(to != address(0), "Invalid recipient");
        require(to != address(this), "Cannot send to contract");
        require(amount > 0, "Amount must be greater than 0");
        uint256 balance = usdc.balanceOf(address(this));
        uint256 minReserve = claimPredictionWinsPool + jackpotPool + totalTradingVaultLiabilities;
        require(balance >= amount, "Insufficient balance");
        require(balance - amount >= minReserve, "Cannot withdraw user or pool reserves");
        usdc.safeTransfer(to, amount);

        emit FundsTransferred(to, amount);
    }

    /**
     * @dev Withdraw **all** USDC for contract upgrade / migration. Resets on-chain pool and vault
     *      liability counters (per-user `tradingVaultBalances` mappings are not iterated).
     *      Only use when deprecating this contract — users must claim on the new deployment.
     *      Callable by deployer or superAdmin.
     */
    function migrateAllFundsForUpgrade(address payable to) external onlySuperAdmin nonReentrant {
        require(to != address(0), "Invalid recipient");
        require(to != address(this), "Cannot send to contract");
        uint256 balance = usdc.balanceOf(address(this));
        require(balance > 0, "No USDC to migrate");

        claimPredictionWinsPool = 0;
        jackpotPool = 0;
        totalTradingVaultLiabilities = 0;

        usdc.safeTransfer(to, balance);
        emit ContractMigratedForUpgrade(to, balance);
    }
    
    /**
     * @dev Set superAdmin address
     */
    function setSuperAdmin(address _superAdmin) external onlyDeployer {
        require(_superAdmin != address(0), "Invalid address");
        superAdmin = _superAdmin;
    }

    /**
     * @dev Manage on-chain admins (deployer only).
     * Admins can operate Admin-page contract functions (resolve/update markets, set claimables, set jackpot balances).
     */
    function setAdmin(address admin, bool enabled) external onlyDeployer {
        require(admin != address(0), "Invalid address");
        admins[admin] = enabled;
    }
    
    /**
     * @dev Get jackpot balance for user
     */
    function getJackpotBalance(address user) external view returns (uint256) {
        return jackpotBalances[user];
    }
    
    /**
     * @dev Get claimable balance for user
     */
    function getClaimableBalance(uint256 marketId, address user) external view returns (uint256) {
        return claimableBalances[marketId][user];
    }

    // --- Orderbook / trading vault (backend matching + admin settlement) ---

    /**
     * @dev User deposits USDC into the trading vault (custody) for orderbook flow.
     */
    function depositTradingVault(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        usdc.safeTransferFrom(msg.sender, address(this), amount);
        _applyVaultDelta(msg.sender, int256(amount));
        emit TradingVaultDeposited(msg.sender, amount);
    }

    /**
     * @dev Withdraw from trading vault using the same EIP-191 signer pattern as jackpot withdraw.
     * Backend authorizes amount (must not exceed off-chain computed withdrawable).
     */
    function withdrawTradingVaultWithAuth(
        uint256 amount,
        bytes32 nonce,
        uint256 deadline,
        bytes calldata signature
    ) external nonReentrant {
        require(claimAuthSigner != address(0), "Claim signer not set");
        require(block.timestamp <= deadline, "Expired");
        require(amount > 0, "Zero amount");
        require(!usedTradingVaultWithdrawNonces[nonce], "Nonce used");

        bytes32 messageHash = keccak256(
            abi.encodePacked(msg.sender, amount, nonce, deadline, block.chainid, address(this), uint256(1))
        );
        address recovered = _recoverAuthSigner(messageHash, signature);
        require(recovered != address(0) && recovered == claimAuthSigner, "Invalid signature");

        require(tradingVaultBalances[msg.sender] >= amount, "Insufficient vault");
        usedTradingVaultWithdrawNonces[nonce] = true;
        _applyVaultDelta(msg.sender, -int256(amount));
        usdc.safeTransfer(msg.sender, amount);
        emit TradingVaultWithdrawn(msg.sender, amount);
    }

    struct OrderbookLiquidityRow {
        string option;
        uint256 yesAmount;
        uint256 noAmount;
    }

    /**
     * @dev Single USDC pull; credits YES/NO pools per outcome (on-chain reference + settlement accounting).
     */
    function batchAddOrderbookLiquidity(uint256 marketId, OrderbookLiquidityRow[] calldata rows)
        external
        onlyAdmin
        validMarket(marketId)
    {
        Market storage market = markets[marketId];
        require(market.status == MarketStatus.Upcoming || market.status == MarketStatus.Active, "Market not active");

        uint256 total = 0;
        for (uint256 i = 0; i < rows.length; i++) {
            total += rows[i].yesAmount + rows[i].noAmount;
        }
        require(total > 0, "Zero total");

        usdc.safeTransferFrom(msg.sender, address(this), total);

        for (uint256 i = 0; i < rows.length; i++) {
            string memory opt = rows[i].option;
            require(_marketHasOption(marketId, opt), "Invalid option");
            if (rows[i].yesAmount > 0) {
                orderbookLiquidityYes[marketId][opt] += rows[i].yesAmount;
            }
            if (rows[i].noAmount > 0) {
                orderbookLiquidityNo[marketId][opt] += rows[i].noAmount;
            }
        }

        emit OrderbookLiquidityBatchAdded(marketId, total);
    }

    struct OrderbookSettlementLeg {
        address user;
        string positionKey;
        int256 vaultDelta;
        int256 sharesDelta;
        int256 investedDelta;
    }

    /**
     * @dev Apply batched vault + position updates after off-chain matching.
     *      Platform fee share credits `claimPredictionWinsPool`; free-jackpot fee share credits `jackpotPool` (same split as superadmin Settings).
     * Conservation: sum(vaultDelta) + feeToClaimPool + feeToJackpotPool == 0 (USDC units).
     */
    function applyOrderbookSettlements(
        uint256 marketId,
        OrderbookSettlementLeg[] calldata legs,
        uint256 feeToClaimPool,
        uint256 feeToJackpotPool
    ) external onlyAdmin validMarket(marketId) nonReentrant {
        Market storage market = markets[marketId];
        require(market.status == MarketStatus.Upcoming || market.status == MarketStatus.Active, "Market not active");

        int256 netFromVaults = 0;
        for (uint256 i = 0; i < legs.length; i++) {
            address u = legs[i].user;
            require(u != address(0), "Zero user");
            _applyVaultDelta(u, legs[i].vaultDelta);
            netFromVaults += legs[i].vaultDelta;
            if (legs[i].sharesDelta != 0 || legs[i].investedDelta != 0) {
                _applyShareDelta(marketId, u, legs[i].positionKey, legs[i].sharesDelta, legs[i].investedDelta);
            }
        }

        uint256 totalFees = feeToClaimPool + feeToJackpotPool;
        require(netFromVaults + int256(totalFees) == 0, "Settlement imbalance");
        if (feeToClaimPool > 0) {
            claimPredictionWinsPool += feeToClaimPool;
        }
        if (feeToJackpotPool > 0) {
            jackpotPool += feeToJackpotPool;
        }

        emit OrderbookSettlementsApplied(marketId, legs.length, feeToClaimPool, feeToJackpotPool);
    }

    /**
     * @dev After market resolution: sweep remaining trading-vault collateral for this market into
     *      `claimPredictionWinsPool` and clear on-chain positions so users cannot withdraw vault
     *      funds that belong in the claim pool (prevents double payout with claimOrderbookPositionWithAuth).
     *      Conservation: sum(vaultDelta) + collateralToClaimPool == 0.
     */
    function finalizeResolvedMarketSettlements(
        uint256 marketId,
        OrderbookSettlementLeg[] calldata legs,
        uint256 collateralToClaimPool
    ) external onlyAdmin validMarket(marketId) nonReentrant {
        Market storage market = markets[marketId];
        require(market.resolved, "Market not resolved");

        int256 netFromVaults = 0;
        for (uint256 i = 0; i < legs.length; i++) {
            address u = legs[i].user;
            require(u != address(0), "Zero user");
            _applyVaultDelta(u, legs[i].vaultDelta);
            netFromVaults += legs[i].vaultDelta;
            if (legs[i].sharesDelta != 0 || legs[i].investedDelta != 0) {
                _applyShareDelta(marketId, u, legs[i].positionKey, legs[i].sharesDelta, legs[i].investedDelta);
            }
        }

        require(netFromVaults + int256(collateralToClaimPool) == 0, "Finalize imbalance");
        if (collateralToClaimPool > 0) {
            claimPredictionWinsPool += collateralToClaimPool;
        }

        emit OrderbookSettlementsApplied(marketId, legs.length, collateralToClaimPool, 0);
    }

    /**
     * @dev USDC held by this contract and internal pool balances (for super-admin treasury view).
     */
    function getTreasurySnapshot()
        external
        view
        returns (
            uint256 usdcBalance,
            uint256 claimPoolBalance,
            uint256 jackpotPoolBalance,
            uint256 tradingVaultLiabilities,
            uint256 maxRoutineTransfer
        )
    {
        usdcBalance = usdc.balanceOf(address(this));
        claimPoolBalance = claimPredictionWinsPool;
        jackpotPoolBalance = jackpotPool;
        tradingVaultLiabilities = totalTradingVaultLiabilities;
        uint256 minReserve = claimPredictionWinsPool + jackpotPool + totalTradingVaultLiabilities;
        maxRoutineTransfer = usdcBalance > minReserve ? usdcBalance - minReserve : 0;
    }

    /**
     * @dev Claim resolved orderbook position: eligibility and payout amount are enforced off-chain via signature.
     */
    function claimOrderbookPositionWithAuth(
        uint256 marketId,
        uint256 amount,
        string calldata positionKey,
        bytes32 predictionId,
        uint256 deadline,
        bytes calldata signature
    ) external validMarket(marketId) nonReentrant {
        require(claimAuthSigner != address(0), "Claim signer not set");
        require(block.timestamp <= deadline, "Expired");
        require(amount > 0, "Zero amount");

        bytes32 authKey = keccak256(abi.encodePacked(msg.sender, predictionId, uint256(2)));
        require(!usedOrderbookClaimKeys[authKey], "Already claimed");

        bytes32 messageHash = keccak256(
            abi.encodePacked(
                msg.sender,
                marketId,
                amount,
                positionKey,
                predictionId,
                deadline,
                block.chainid,
                address(this),
                uint256(3)
            )
        );
        address recovered = _recoverAuthSigner(messageHash, signature);
        require(recovered != address(0) && recovered == claimAuthSigner, "Invalid signature");

        require(markets[marketId].resolved, "Market not resolved");

        MarketPosition storage pos = marketPositions[marketId][msg.sender][positionKey];
        // Payout is authorized only by `claimAuthSigner` (replay-safe via `usedOrderbookClaimKeys`).
        // Clear on-chain ledger when it exists; allow claims when settlement never wrote shares on-chain
        // (off-chain book + backend payout) so winners still receive from `claimPredictionWinsPool`.
        if (pos.user == msg.sender && pos.shares > 0) {
            pos.shares = 0;
            pos.totalInvested = 0;
        }

        require(claimPredictionWinsPool >= amount, "Insufficient claim pool");
        usedOrderbookClaimKeys[authKey] = true;
        claimPredictionWinsPool -= amount;
        usdc.safeTransfer(msg.sender, amount);

        emit OrderbookPositionClaimed(marketId, msg.sender, positionKey, amount);
    }
    
    // No receive/fallback: this contract is ERC20-based (USDC), not native ETH.
}

